const d = $input.first().json;
const body = d.body || d;
const name       = body.name || '';
const biz        = body.businessName || '';
const prof       = body.profession || 'professional';
const loc        = body.location || '';
const socialName = body.socialName  || name;
const locNote    = loc ? `, ${loc}` : '';

// Name variations for people-finder style search
const nameParts  = socialName.trim().split(/\s+/);
const firstName  = nameParts[0] || '';
const lastName   = nameParts[nameParts.length - 1] || '';
const nameRev    = lastName !== firstName ? `${lastName}, ${firstName}` : '';
const nameVars   = [...new Set([socialName, name, nameRev, `${firstName} ${lastName}`])].filter(Boolean).map(n => `"${n}"`).join(' OR ');

// Confirmed profiles from user input
const known = [];
if (body.linkedinUrl)  known.push(`LinkedIn: ${body.linkedinUrl}`);
if (body.facebookUrl)  known.push(`Facebook: ${body.facebookUrl}`);
if (body.twitterUrl)   known.push(`Twitter/X: ${body.twitterUrl}`);
if (body.youtubeUrl)   known.push(`YouTube: ${body.youtubeUrl}`);
if (body.instagramUrl) known.push(`Instagram: ${body.instagramUrl}`);
if (body.website)      known.push(`Website: ${body.website}`);
if (Array.isArray(body.otherProfiles)) {
  body.otherProfiles.forEach(p => { if (p && p.platform && p.url) known.push(`${p.platform}: ${p.url}`); });
}
const confirmedBlock = known.length > 0
  ? `
CONFIRMED PROFILES (user-provided, treat as verified — analyze quality & activity):
${known.join('
')}
`
  : '';

// Profession-specific database hints
const profDB = prof.toLowerCase().includes('mortgage') || prof.toLowerCase().includes('lender')
  ? `- NMLS Consumer Access: Search nmlsconsumeraccess.org for "${name}" — every licensed mortgage originator has a public NMLS profile
`
  : prof.toLowerCase().includes('realtor') || prof.toLowerCase().includes('real estate')
  ? `- State real estate license lookup: Search "${name}" real estate license "${loc}" DRE OR state licensing board
`
  : '';

const query = `TASK: Comprehensive digital presence audit using people-finder and professional database methodology.

SUBJECT:
- Name variations to search: ${nameVars}
- Profession: ${prof}${locNote}
- Business: "${biz}"
${body.website ? `- Website: ${body.website}
` : ''}${confirmedBlock}
METHODOLOGY — search all of the following independently:

A. SOCIAL MEDIA (search by person name AND business name separately):
1. LinkedIn: (${nameVars}) site:linkedin.com AND (${nameVars}) "${prof}" linkedin AND "${biz}" site:linkedin.com
2. Facebook: (${nameVars}) site:facebook.com AND "${biz}" facebook page
3. Twitter/X: (${nameVars}) site:twitter.com OR site:x.com AND "${biz}" twitter
4. YouTube: (${nameVars}) site:youtube.com AND "${biz}" youtube channel
5. Instagram: (${nameVars}) site:instagram.com AND "${biz}" instagram
6. TikTok: (${nameVars}) site:tiktok.com AND "${biz}" tiktok
7. Pinterest: (${nameVars}) site:pinterest.com
8. Substack: (${nameVars}) site:substack.com
9. Medium: (${nameVars}) site:medium.com

B. BUSINESS & REVIEW DIRECTORIES (search by business name AND person name):
10. Google Business Profile: "${biz}" "${loc}" google maps business
11. Yelp: "${biz}" site:yelp.com "${loc}"
12. BBB (Better Business Bureau): "${biz}" site:bbb.org AND (${nameVars}) bbb.org
13. Crunchbase: "${biz}" site:crunchbase.com
14. Trustpilot: "${biz}" site:trustpilot.com
15. Bing Places: "${biz}" "${loc}" bing places business
16. Apple Business Connect: "${biz}" "${loc}" apple maps
17. Zillow / Realtor.com: (${nameVars}) mortgage OR realtor zillow.com OR realtor.com

C. PROFESSIONAL & PUBLIC DATABASES:
${profDB}- State business registry: "${biz}" secretary of state business filing OR "${biz}" LLC registration "${loc}"
- Professional license search: (${nameVars}) professional license "${prof}" "${loc}"
- Public records / people finders: (${nameVars}) "${loc}" site:whitepages.com OR site:spokeo.com OR site:zabasearch.com OR site:intelius.com
- Voter registration / public records: (${nameVars}) "${loc}" public record
- Court records: (${nameVars}) court case OR judgment OR lawsuit "${loc}" PACER
- Property records: (${nameVars}) "${loc}" property owner OR tax record

D. PERSONAL WEBSITE & BLOG:
- "${biz}" official website
- (${nameVars}) "${prof}" website OR blog OR about page

E. NEGATIVE CONTENT (search separately for name and business):
- (${nameVars}) complaint OR scam OR fraud OR lawsuit OR "bad review" OR derogatory OR ripoff
- "${biz}" complaint OR scam OR fraud OR lawsuit OR BBB complaint OR negative review
- Reddit: site:reddit.com (${nameVars}) OR site:reddit.com "${biz}"
- Google reviews and Yelp reviews for "${biz}"
- News articles: (${nameVars}) OR "${biz}" news article OR press release (positive or negative)

F. IMPERSONATORS & SIMILAR NAMES:
- Find anyone else using (${nameVars}) on social media who is NOT this person
- Find any domain names similar to "${biz}" that might be copycats
- Find accounts using "${biz}" that are not official

For EVERY platform and database above:
- Provide the exact URL if found
- Quote any reviews, ratings, or negative content verbatim
- Note any discrepancies or red flags
- If genuinely not found after active search, say so explicitly
- If uncertain whether a result belongs to this specific person, include it with a note`;

return [{ json: { input: body, query } }];

const input     = $('Build Query').first().json.input;
const rawSearch = $input.first().json;
const research  = rawSearch?.choices?.[0]?.message?.content || '';

if (!research) {
  return [{ json: { error: 'Perplexity returned no data', raw: JSON.stringify(rawSearch).slice(0, 300) } }];
}

const socialNote = input.socialName && input.socialName !== input.name ? ` (also known as ${input.socialName} on social media)` : '';
const confirmedUrls = [input.linkedinUrl, input.facebookUrl, input.twitterUrl, input.youtubeUrl, input.instagramUrl, input.website].filter(Boolean);
const confirmedNote = confirmedUrls.length > 0 ? `\nNOTE: The following profile URLs were CONFIRMED by the person and must be marked as found=true: ${confirmedUrls.join(', ')}` : '';
const prompt = `You are a digital presence analyst. Based on this web research, produce a scored audit report for ${input.name}${socialNote} (${input.businessName}, ${input.profession}).${confirmedNote}

WEB RESEARCH FINDINGS:
${research}

Return ONLY valid JSON (no markdown, no code fences, no explanation) matching this exact schema:
{
  "overallScore": <integer 0-100>,
  "verdict": "Digital Danger Zone" | "Needs Work" | "Building Momentum" | "Authority Status",
  "summary": "<2-3 sentence plain-English summary of their digital presence>",
  "platforms": [
    { "platform": "<name>", "icon": "<1 emoji>", "found": <boolean>, "url": <string or null>, "score": <0-100>, "verified": <boolean>, "notes": "<short note about their presence here>" }
  ],
  "negativeContent": [
    { "source": "<platform/site name>", "url": <string or null>, "snippet": "<what was said>", "severity": "low" | "medium" | "high", "type": "review" | "complaint" | "news" | "forum" | "derogatory" | "other" }
  ],
  "copycats": [
    { "platform": "<name>", "url": <string or null>, "description": "<what was found>", "riskLevel": "low" | "medium" | "high" }
  ],
  "similarProfiles": [
    { "name": "<full name or business>", "platform": "<where found>", "url": <string or null>, "similarity": "<why it shares the name>" }
  ],
  "recommendations": [
    { "priority": "immediate" | "high" | "medium" | "low", "category": "<category>", "action": "<specific action to take>", "impact": "<why this matters for leads>", "difficulty": "easy" | "medium" | "hard" }
  ],
  "scannedAt": "${new Date().toISOString()}"
}

Rules:
- Always include these 18 platforms: Google Business Profile, LinkedIn, Facebook, Instagram, X (Twitter), TikTok, YouTube, Yelp, BBB, Crunchbase, Trustpilot, Bing Places, Apple Business Connect, Substack, Medium, Zillow, Realtor.com, Personal Website
- Set found=true only when the research explicitly mentions a confirmed profile URL for this specific person
- Set found=false only when the research actively searched and found NO profile — not merely because it was not mentioned
- If the research is ambiguous or the name is common, set found=false but write in notes: "Name is common — manual verification recommended" with a direct search link
- Provide exactly 6 recommendations ranked by priority
- Score: 0-39=Digital Danger Zone, 40-64=Needs Work, 65-84=Building Momentum, 85-100=Authority Status
- Base score on: number of platforms confirmed found, profile completeness, review quality, absence of negatives, verified accounts
- Do NOT penalize heavily for platforms that are "unverified" due to common name ambiguity — note this in the summary`;

return [{ json: { input, prompt } }];

const raw = $input.first().json?.content?.[0]?.text || '';
let result;
try {
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  result = JSON.parse(cleaned);
} catch (e) {
  return [{ json: { error: 'Failed to parse AI response', raw: raw.slice(0, 500) } }];
}
return [{ json: result }];
